    // Utility class for creating deep links programmatically
    public static class DeepLinkBuilder {

        public static Uri buildProfileLink(String userId) {
            return new Uri.Builder()
                    .scheme(SCHEME)
                    .authority("profile")
                    .appendPath(userId)
                    .build();
        }

        public static Uri buildPaymentConfirmLink(String transactionId) {
            Uri.Builder builder = new Uri.Builder()
                    .scheme(SCHEME)
                    .authority("payment")
                    .appendPath("confirm");
            if (transactionId != null) {
                builder.appendQueryParameter("transaction_id", transactionId);
            }
            return builder.build();
        }

        public static Uri buildAdminSettingsLink() {
            return new Uri.Builder()
                    .scheme(SCHEME)
                    .authority("admin")
                    .appendPath("settings")
                    .build();
        }

        public static Uri addCampaignParams(Uri baseUri, String source, String medium, String campaign) {
            Uri.Builder builder = baseUri.buildUpon();
            if (source != null) builder.appendQueryParameter("utm_source", source);
            if (medium != null) builder.appendQueryParameter("utm_medium", medium);
            if (campaign != null) builder.appendQueryParameter("utm_campaign", campaign);
            return builder.build();
        }
    }
